// ├ö─Ż─╣  KONFIGUROVATELNÔöť├ź PARAMETRY - UPRAV HODNOTY N├Ź┼ŻE           ├ö─Ż─╣
// ├ö─Ż├ť├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż┼ü

const CONFIG = {
    // === TEPLOTY (ÔöČÔľĹC) ===
    TEPLOTA_MAX: 69,        // MaximÔöť├şlnÔöť┼č teplota bojleru
    TEPLOTA_VYSOKA: 60,     // VysokÔöť├ş teplota (b─Ť┼żnÔöť┼╗ ohÔö╝├ľev)
    TEPLOTA_STREDNI: 58,    // StÔö╝├ľednÔöť┼č teplota (levnÔöť├ş elektÔö╝├ľina)
    TEPLOTA_MIN: 20,        // MinimÔöť├şlnÔöť┼č teplota (vypnuto)
    TEPLOTA_POVINNY_SOLAR: 40, // Teplota v povinnÔöť┼╗ch hodinÔöť├şch kdyÔö╝┼╝ zÔöť┼čtra velkÔöť┼╗ solÔöť├şr

    // === HYSTEREZE A SPOTÔö╝┼ŤEBA ===
    HYSTEREZE: 500,         // Hystereze v W (zabraÔö╝┼éuje oscilaci)
    SPOTREBA_BOJLER: 2500,  // SpotÔö╝├ľeba bojleru v W

    // === CENOVÔöť├ź PRAHY ===
    PRICE_LEVEL_LEVNY: 6,   // Level ceny (1-24), kdy je proud levnÔöť┼╗
    CENA_KWH_LEVNA: 2.6,    // Cena v KÔöÇ┼╣/kWh, kdy je proud levnÔöť┼╗

    // === FORECAST ===
    FORECAST_THRESHOLD: 35000  // PrÔöť├şh forecastu v Wh (35kWh)
};

// ├ö─Ż├Â├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż┼Ü
// ├ö─Ż─╣  ULOÔö╝┼╗ENÔöť┼╣ DO FLOW PROMÔöÇ├ťNNÔöť┼üCH - NEMÔöÇ├ťNIT                      ├ö─Ż─╣
// ├ö─Ż├ť├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż├ë├ö─Ż┼ü

for (const [key, value] of Object.entries(CONFIG)) {
    flow.set(key, value);
}

msg.payload = {
    status: "Konfigurace uloÔö╝┼╝ena",
    config: CONFIG
};

node.status({fill: "green", shape: "dot", text: "Konfigurace uloÔö╝┼╝ena"});
//node.warn("Bojler konfigurace uloÔö╝┼╝ena: " + JSON.stringify(CONFIG));

return msg;

// 🧠 Rozhodovací logika bojleru — cílová teplota dle přebytku, ceny, forecastu, FVE módu
var TEPLOTA_MAX = flow.get("TEPLOTA_MAX")||69, TEPLOTA_VYSOKA = flow.get("TEPLOTA_VYSOKA")||60;
var TEPLOTA_STREDNI = flow.get("TEPLOTA_STREDNI")||58, TEPLOTA_MIN = flow.get("TEPLOTA_MIN")||20;
var TEPLOTA_POVINNY_SOLAR = flow.get("TEPLOTA_POVINNY_SOLAR")||40;
var HYSTEREZE = flow.get("HYSTEREZE")||500, SPOTREBA_BOJLER = flow.get("SPOTREBA_BOJLER")||2500;
var PRICE_LEVEL_LEVNY = flow.get("PRICE_LEVEL_LEVNY")||3, CENA_KWH_LEVNA = flow.get("CENA_KWH_LEVNA")||2.6;
var FORECAST_THRESHOLD = flow.get("FORECAST_THRESHOLD")||35000;
var forecast_dnes = global.get("forecast_vyroba_dnes")||0, forecast_zitra = global.get("forecast_vyroba_zitra")||0;
var cerpadlo_topi = global.get("cerpadlo_topi")===true;
var fve_config = global.get("fve_config")||{}, max_grid = fve_config.max_spotreba_sit_w||22000, min_soc = fve_config.min_soc||20;
var fve_mode = global.get("fve_current_mode")||"";
var is_zaporna_cena = fve_mode==="zaporna_nakupni_cena", is_zakaz_pretoku = fve_mode==="zakaz_pretoku";
var climate_entity = global.get("homeassistant.homeAssistant.states['climate.smart_socket_thermostat_24090276694597600801c4e7ae0a2e53']")||{};
var aktualni_target = parseFloat((climate_entity.attributes||{}).temperature)||0;
var jsme_doma = msg.jsme_doma==="on", rychle_voda = msg.rychle_voda==="on";
var teplota_bojleru = msg.teplota_bojleru||0, spotreba_bojleru = msg.spotreba_bojleru||0;
var battery = msg.battery_percent||0, rozdil_vyroby = msg.rozdil_vyroby||0;
var letni_rezim = msg.letni_rezim==="on", auto_hlad = msg.auto_hlad==="on", auto_automatizace = msg.auto_automatizace==="on";
var price_level = msg.price_level||24, cena_kwh = msg.cena_kwh||10;
var celkova_spotreba = msg.celkova_spotreba||0, spotreba_ze_site = msg.spotreba_ze_site||0;
var cas_minuty = new Date().getHours()*60 + new Date().getMinutes();
var je_povinny_cas = cas_minuty >= 17*60 && cas_minuty <= 19*60+30, bojler_ohriva = spotreba_bojleru > 100;
var sit_limit = max_grid - (fve_config.safety_margin_w||2000);
var muzeme_zapnout = bojler_ohriva || ((sit_limit - celkova_spotreba) >= SPOTREBA_BOJLER);
var ma_prostor_pod_jisticem = (max_grid - spotreba_ze_site) >= SPOTREBA_BOJLER;
var PRAH_ZAPNUTI_MAX = 4000+SPOTREBA_BOJLER+HYSTEREZE, PRAH_VYPNUTI_MAX = 4000;
var PRAH_ZAPNUTI_VYSOKA = SPOTREBA_BOJLER+HYSTEREZE, PRAH_VYPNUTI_VYSOKA = -HYSTEREZE;
var je_levna = (price_level<=PRICE_LEVEL_LEVNY)||(cena_kwh<=CENA_KWH_LEVNA);
var slunecny_den_dnes = forecast_dnes > FORECAST_THRESHOLD, slunecny_den_zitra = forecast_zitra > FORECAST_THRESHOLD;
var cilova_teplota = TEPLOTA_MIN, duvod = "";

// ROZHODOVACÍ LOGIKA (dle priority, první splněná podmínka vyhraje)
if (!jsme_doma) { cilova_teplota = TEPLOTA_MIN; duvod = "Není doma"; }
else if (rychle_voda) { cilova_teplota = TEPLOTA_MAX; duvod = "Rychle voda"; }
// §4.10: Záporná cena → MAX pokud prostor pod jističem, jinak normální logika
else if (is_zaporna_cena && ma_prostor_pod_jisticem) {
    cilova_teplota = TEPLOTA_MAX; duvod = "Záporná! Volno:"+Math.round(max_grid-spotreba_ze_site)+"W";
}
// §4.6: Zákaz přetoků — topíme jen z přebytku/baterie, ne ze sítě
else if (is_zakaz_pretoku) {
    if (rozdil_vyroby >= SPOTREBA_BOJLER) { cilova_teplota = TEPLOTA_MAX; duvod = "Zákaz+přebytek "+Math.round(rozdil_vyroby/1000)+"kW"; }
    else if (battery > min_soc+5) { cilova_teplota = TEPLOTA_STREDNI; duvod = "Zákaz bat:"+battery+"%→boiler"; }
    else { cilova_teplota = TEPLOTA_MIN; duvod = "Zákaz bat:"+battery+"%→čekám"; }
}
// Povinný čas 17:00-19:30, voda < 58°C
else if (je_povinny_cas && teplota_bojleru < 58) {
    if (!muzeme_zapnout) { cilova_teplota = TEPLOTA_MIN; duvod = "Pov.čas limit sítě"; }
    else if (slunecny_den_zitra) { cilova_teplota = TEPLOTA_POVINNY_SOLAR; duvod = "Pov.čas zítra sol→"+TEPLOTA_POVINNY_SOLAR+"°C"; }
    else { cilova_teplota = TEPLOTA_VYSOKA; duvod = "Pov.ohřev 17-19:30"; }
}
// NIBE topí a přebytek nestačí → OFF
else if (cerpadlo_topi && rozdil_vyroby < PRAH_ZAPNUTI_VYSOKA) {
    cilova_teplota = TEPLOTA_MIN; duvod = "NIBE přeb:"+Math.round(rozdil_vyroby/1000)+"kW";
}
// Baterie plné (>96%) — využijeme solární přebytek
else if (battery > 96) {
    var prah_max = bojler_ohriva ? PRAH_VYPNUTI_MAX : PRAH_ZAPNUTI_MAX;
    var prah_vysoka = bojler_ohriva ? PRAH_VYPNUTI_VYSOKA : PRAH_ZAPNUTI_VYSOKA;
    if (rozdil_vyroby > prah_max) {
        cilova_teplota = (auto_hlad && auto_automatizace) ? TEPLOTA_VYSOKA : TEPLOTA_MAX;
        duvod = (auto_hlad ? "Přeb+auto " : "Bat plné+přeb ")+Math.round(rozdil_vyroby/1000)+"kW";
    } else if (rozdil_vyroby > prah_vysoka) {
        cilova_teplota = TEPLOTA_VYSOKA; duvod = "Přeb "+Math.round(rozdil_vyroby/1000)+"kW";
    } else if (bojler_ohriva && rozdil_vyroby > -SPOTREBA_BOJLER) {
        cilova_teplota = flow.get("posledni_cilova_teplota")||TEPLOTA_MIN; duvod = "Hystereze "+cilova_teplota+"°C";
    } else {
        if (!letni_rezim && je_levna && muzeme_zapnout) { cilova_teplota = TEPLOTA_STREDNI; duvod = "Levná L"+price_level; }
        else { cilova_teplota = TEPLOTA_MIN; duvod = letni_rezim ? "Léto čeká" : "Drahá/málo"; }
    }
}
// Baterie nejsou plné — standardní logika
else {
    var prah_v = bojler_ohriva ? PRAH_VYPNUTI_VYSOKA : PRAH_ZAPNUTI_VYSOKA;
    var prah_m = bojler_ohriva ? PRAH_VYPNUTI_MAX : PRAH_ZAPNUTI_MAX;
    if (rozdil_vyroby > prah_m) {
        cilova_teplota = TEPLOTA_MAX; duvod = "Velký přeb "+Math.round(rozdil_vyroby/1000)+"kW bat:"+battery+"%";
    } else if (rozdil_vyroby > prah_v) {
        cilova_teplota = TEPLOTA_VYSOKA; duvod = "Přeb "+Math.round(rozdil_vyroby/1000)+"kW bat:"+battery+"%";
    } else if (bojler_ohriva && rozdil_vyroby > -SPOTREBA_BOJLER) {
        cilova_teplota = flow.get("posledni_cilova_teplota")||TEPLOTA_MIN; duvod = "Hystereze "+cilova_teplota+"°C";
    } else if (letni_rezim && slunecny_den_dnes) {
        cilova_teplota = TEPLOTA_MIN; duvod = "Léto fc:"+Math.round(forecast_dnes/1000)+"kWh";
    } else if (!letni_rezim && je_levna && muzeme_zapnout) {
        cilova_teplota = TEPLOTA_STREDNI; duvod = "Levná L"+price_level+" "+cena_kwh+"Kč";
    } else { cilova_teplota = TEPLOTA_MIN; duvod = letni_rezim?"Léto solar":!muzeme_zapnout?"Limit sítě":"Drahá"; }
}

flow.set("posledni_cilova_teplota", cilova_teplota);
var stav_klimatu = (climate_entity||{}).state||"unavailable";
if (stav_klimatu==="unavailable") { node.status({fill:"red",shape:"ring",text:"Meross UNAVAIL"}); return null; }
if (cilova_teplota===aktualni_target) { node.status({fill:"blue",shape:"dot",text:cilova_teplota+"/"+aktualni_target+"°C BEZ ZMĚNY "+duvod}); return null; }
msg.payload = {teplota: cilova_teplota, duvod: duvod, debug: {
    jsme_doma: jsme_doma, rychle_voda: rychle_voda, teplota_bojleru: teplota_bojleru, battery: battery,
    rozdil_vyroby: rozdil_vyroby, letni_rezim: letni_rezim, price_level: price_level, cena_kwh: cena_kwh,
    je_levna: je_levna, celkova_spotreba: celkova_spotreba, muzeme_zapnout: muzeme_zapnout, fve_mode: fve_mode
}};
var barva = cilova_teplota >= TEPLOTA_VYSOKA ? "green" : cilova_teplota >= TEPLOTA_STREDNI ? "yellow" : "grey";
node.status({fill: barva, shape: bojler_ohriva ? "ring" : "dot", text: cilova_teplota+"°C "+duvod});
return msg;
